367:     pub fn backspace(self: *State) void {
368:         // buffer_length must be positive for backspace.
369:         assert(self.buffer_length > 0);
370: 
371:         // Input mode must be either .literal or .telex.
372:         assert(self.mode == .literal or self.mode == .telex);
373: 
374:         if (self.literal_index) |literal_index| {
375:             // Input mode must be .telex when literal_index is set.
376:             assert(self.mode == .telex);
377:             // literal_index must be within buffer range when set.
378:             assert(literal_index < self.buffer_length);
379:         }
380: 
381:         // decrease the buffer_length to match the backspace.
382:         self.buffer_length -= 1;
383:         // b cause backspace doesn't retro-modify the buffer, unset the buffer_modification_index.
384:         self.buffer_modification_index = null;
385:         // if the literal_index is out of buffer range, unset it.
386:         if (self.literal_index != null and self.literal_index.? == self.buffer_length) {
387:             self.literal_index = null;
388:         }
